customCSS:
/* Gruvbox Dark - Retro Warmth */
@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@300;400;500;600;700&family=IBM+Plex+Mono&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 30% 20%, rgba(254, 128, 25, 0.18), transparent),
    radial-gradient(ellipse 500px 350px at 70% 80%, rgba(131, 165, 152, 0.12), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(235, 219, 178, 0.12);
  background: rgba(60, 56, 54, 0.9);
  border-radius: 6px;
}

.stat-card::before {
  background: linear-gradient(90deg, #fb4934, #fe8019, #fabd2f, #b8bb26);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(254, 128, 25, 0.3);
  box-shadow: 0 4px 16px rgba(254, 128, 25, 0.08);
}

.stat-value {
  text-shadow: none;
}

.celebration-title {
  color: #fabd2f !important;
  text-shadow: 0 0 20px rgba(250, 189, 47, 0.4);
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(60, 56, 54, 0.7);
  border: 1px solid rgba(235, 219, 178, 0.08);
  border-radius: 6px;
}

.miner-card:hover {
  border-color: rgba(184, 187, 38, 0.2);
}
